INSERT INTO `route` (`id`, `user_id`, `name`, `destination`, `days`, `budget`, `preference`, `ai_summary`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, '上海3日经典城市观光', '上海', 3, 2500.00, '城市观光', 'AI建议：第一天安排外滩、南京路与豫园，快速建立上海城市印象；第二天前往东方明珠、上海博物馆和武康路，兼顾现代都市与历史街区；第三天加入海昌海洋公园或自由活动，整体节奏适合首次到访游客。', 1, '2025-07-01 10:00:00', '2025-07-01 10:00:00'),
(2, 2, '北京4日深度历史文化游', '北京', 4, 3200.00, '历史文化', 'AI建议：建议采用“中轴线+皇家园林+长城”的经典组合，前两日聚焦天安门、故宫与南锣鼓巷，后两日安排长城、颐和园和天坛，兼顾历史厚度与出行强度。', 1, '2025-07-02 11:30:00', '2025-07-02 11:30:00'),
(3, 3, '杭州2日慢生活自然风光', '杭州', 2, 1500.00, '自然风光', 'AI建议：将西湖环线与灵隐寺、龙井村组合，上午游览、下午休闲、傍晚赏景的节奏最适合杭州；整体路线偏慢游，适合希望放松身心的游客。', 1, '2025-07-03 09:15:00', '2025-07-03 09:15:00'),
(4, 5, '成都4日美食休闲之旅', '成都', 4, 2800.00, '美食', 'AI建议：优先安排宽窄巷子、锦里、大熊猫基地和人民公园，穿插火锅、串串和茶馆体验；建议晚间活动占比更高，符合成都慢节奏生活方式。', 1, '2025-07-04 14:00:00', '2025-07-04 14:00:00'),
(5, 6, '三亚3日海滨度假', '三亚', 3, 3500.00, '海滨度假', 'AI建议：以亚龙湾、蜈支洲岛和椰梦长廊为核心，适合海滨度假与拍照打卡；建议把潜水、海岛出海与日落观景分开安排，提升体验完整度。', 1, '2025-07-05 16:30:00', '2025-07-05 16:30:00'),
(6, 7, '西安3日历史文化亲子游', '西安', 3, 2600.00, '亲子游', 'AI建议：将兵马俑、城墙骑行、大雁塔和大唐不夜城串联，形成“白天学历史、晚上看灯光”的亲子路线，体验感和教育性兼顾。', 1, '2025-07-06 08:45:00', '2025-07-06 08:45:00'),
(7, 8, '厦门3日摄影打卡之旅', '厦门', 3, 2200.00, '摄影游', 'AI建议：鼓浪屿、厦门大学、沙坡尾和环岛路适合作为摄影主线，建议早晨拍海景、午后拍街景、傍晚拍日落，出片率较高。', 1, '2025-07-07 13:20:00', '2025-07-07 13:20:00'),
(8, 9, '广州2日美食探店游', '广州', 2, 1200.00, '美食', 'AI建议：以早茶、北京路、沙面和珠江夜游为核心，路线短但节奏紧凑；建议将美食安排在白天、夜景安排在晚上，体验更完整。', 1, '2025-07-08 10:40:00', '2025-07-08 10:40:00'),
(9, 10, '上海杭州4日江南慢旅行', '上海-杭州', 4, 3000.00, '慢旅行', 'AI建议：双城路线建议采用“上海现代都市+杭州江南水乡”的组合，前半程留给上海城市体验，后半段转入杭州慢节奏游览，舒适度更高。', 1, '2025-07-09 07:50:00', '2025-07-09 07:50:00'),
(10, 11, '北京5日皇家园林之旅', '北京', 5, 4000.00, '历史文化', 'AI建议：适合深度历史爱好者，建议将故宫、长城、颐和园、天坛、南锣鼓巷等点位分层安排，避免单日过度拥挤并提升整体叙事感。', 1, '2025-07-10 12:10:00', '2025-07-10 12:10:00'),
(11, 13, '上海3日夜景打卡之旅', '上海', 3, 2000.00, '夜景', 'AI建议：推荐采用“白天城市漫游、夜晚集中拍摄”的方式，外滩、东方明珠和武康路是高优先级拍摄点，能明显提升行程记忆点。', 1, '2025-07-11 18:30:00', '2025-07-11 18:30:00'),
(12, 14, '成都3日亲子熊猫之旅', '成都', 3, 2400.00, '亲子游', 'AI建议：大熊猫基地作为首日主线，后续搭配锦里、宽窄巷子和人民公园，节奏轻松且适合家庭出行，建议中午安排休息时段。', 1, '2025-07-12 09:00:00', '2025-07-12 09:00:00'),
(13, 15, '西安2日速游古城', '西安', 2, 1300.00, '城市观光', 'AI建议：如果时间有限，建议优先覆盖兵马俑、城墙与回民街三个核心点位，形成“文化+美食”双线体验，适合短途高效率旅行。', 1, '2025-07-13 11:00:00', '2025-07-13 11:00:00'),
(14, 16, '三亚5日深度海岛度假', '三亚', 5, 5500.00, '海滨度假', 'AI建议：建议按“海滩休闲、出海潜水、冲浪、日落、自由活动”五段式设计，既避免行程过满，也能最大化体验海岛度假氛围。', 1, '2025-07-14 14:30:00', '2025-07-14 14:30:00'),
(15, 17, '广州3日亲子长隆之旅', '广州', 3, 2800.00, '亲子游', 'AI建议：长隆野生动物世界作为核心，搭配沙面与北京路美食打卡，适合家庭用户；建议将动物园安排在体力最好的第一天。', 1, '2025-07-15 10:20:00', '2025-07-15 10:20:00'),
(16, 19, '成都西安5日双城美食历史游', '成都-西安', 5, 3800.00, '美食', 'AI建议：双城路线建议以“成都美食开场、西安历史收尾”为叙事线，前半程主打川味探店，后半程切换到古都文化，风格反差明显。', 1, '2025-07-16 16:00:00', '2025-07-16 16:00:00'),
(17, 1, '厦门4日文艺清新之旅', '厦门', 4, 2600.00, '摄影游', 'AI建议：鼓浪屿、沙坡尾、厦门大学和环岛路具有很强的文艺感，建议将拍摄与慢游结合，行程整体轻松、氛围感较强。', 1, '2025-07-17 08:30:00', '2025-07-17 08:30:00'),
(18, 2, '杭州3日亲子自然之旅', '杭州', 3, 2000.00, '亲子游', 'AI建议：西湖游船、宋城和西溪湿地可以形成“自然+演艺+亲子”组合，建议增加午间休息点，提升家庭出行舒适度。', 1, '2025-07-18 13:40:00', '2025-07-18 13:40:00'),
(19, 4, '三亚北京6日南北穿越之旅', '三亚-北京', 6, 5000.00, '城市观光', 'AI建议：该路线适合体验地域反差，建议前半段在三亚安排海滨度假，后半段在北京安排历史文化参观，形成鲜明对比。', 0, '2025-07-19 15:10:00', '2025-07-19 15:10:00'),
(20, 20, '上海3日时尚购物美食游', '上海', 3, 3000.00, '美食', 'AI建议：南京路购物、外滩夜景和武康路下午茶是高匹配度组合，适合偏都市感和消费体验的用户，整体风格精致。', 1, '2025-07-20 11:50:00', '2025-07-20 11:50:00');
